query:
SELECT COUNT(*) as total_assets FROM assets;
SELECT COUNT(*) as total_geographic_risks FROM geographicRisks;
SELECT COUNT(*) as assets_without_risks 
FROM assets a 
LEFT JOIN geographicRisks gr ON a.id = gr.assetId 
WHERE gr.id IS NULL;

